package org.example.service;
import org.example.model.dto.RegisterRequest; import org.example.model.entity.User; import org.example.model.enums.UserRole; import org.example.repository.UserRepository; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.stereotype.Service; import java.time.LocalDateTime;
@Service public class AuthService { private final UserRepository repo; private final PasswordEncoder encoder; public AuthService(UserRepository repo, PasswordEncoder encoder){this.repo=repo;this.encoder=encoder;} public void registerUser(RegisterRequest r){register(r,UserRole.ROLE_USER);} public void registerAdmin(RegisterRequest r){register(r,UserRole.ROLE_ADMIN);} private void register(RegisterRequest r, UserRole role){ if(repo.existsByEmail(r.getEmail())) throw new IllegalArgumentException("Пользователь с таким email уже существует"); User u=new User(); u.setName(r.getName()); u.setEmail(r.getEmail()); u.setPassword(encoder.encode(r.getPassword())); u.setRole(role); u.setCreatedAt(LocalDateTime.now()); repo.save(u);} }
